var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"최초의 기억은 텅 빈 방에 홀로 앉아 환청으로 여겨지는 목소리를 듣는 것이었다.","JPN":"最初の記憶は空っぽの部屋に一人で座り、幻聴と思われる声を聞くことだった。","ENG":"My earliest memory was sitting alone in an empty room, listening to a voice that seemed like an auditory hallucination.","TWN":"最初的記憶是獨自坐在空蕩蕩的房間裡，聽到彷彿幻聽般的聲音。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"대대로 단명하는 인도자의 소임을 다하기 위해 조속한 시간 내에 별빛을 느껴야만 했고.","JPN":"代々短命であった導き手の役目を果たすため、早いうちに星の光を感じ取らなければならず。","ENG":"To fulfill the duty of the Star Guide, whose line died young for generations, one had to sense starlight as early as possible.","TWN":"為了履行代代早逝的引導者的職責，必須儘快感受到星光。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"때문에, 어린 후계자가 모든 것을 짊어지는 상황을 부당하다 말하는 사람은 없었다.","JPN":"幼い後継者がすべてを背負う状況を、誰も不当だとは言わなかった。","ENG":"No one spoke of how unjust it was for a child heir to bear the weight of it all.","TWN":"因此，沒有人會說讓年輕的繼承者承擔一切是不公平的。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"모두를 이끄리란 인도자의 전승은 가문에게 있어 그 무엇보다 귀중했으니.","JPN":"皆を導くという導き手の伝承は、家門にとって何よりも重要だったから。","ENG":"The legend of the Guide of leading the people was more precious to the house than anything else.","TWN":"引領眾人的引導者的傳承對家族來說比任何東西都珍貴。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JUDGE_PRIDE_NULL_NULL","text":{"KOREA":"-이상. 제국의 법령에 따라 마왕을 추종한 죄인에게 사형을 고한다.","JPN":"……以上。帝国の法令により、魔王に従った罪人に死刑を告げる。","ENG":"By imperial decree, the traitor who followed the Demon Lord is hereby sentenced to death.","TWN":"-以上。根據帝國法令，對追隨魔王的罪人判處死刑。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"LACKEY_RIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JUDGE_PRIDE_NULL_NULL","text":{"KOREA":"죄인. 집행 전 마지막으로 할 말은 있는가?","JPN":"罪人。執行の前に、最後に残したい言葉はあるか？","ENG":"Prisoner. Any last words before the execution?","TWN":"罪人。執行前有什麼最後的話要說嗎？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"LACKEY_RIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LACKEY_RIDE_NULL_NULL","text":{"KOREA":"위대하신 네헤모트가 이 세계에 안녕을 고하기 위해 강림하셨으니.","JPN":"偉大なるネヘモトがこの世界に最後を告げるために降臨された。","ENG":"The great Nehemoth has descended to bid this world farewell.","TWN":"偉大的貝赫莫特降臨此世，向這個世界告別。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"LACKEY_RIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LACKEY_RIDE_NULL_NULL","text":{"KOREA":"미천한 네놈들은 나헤마의 불꽃에 휩싸여 재로 돌아갈 것이다…!!","JPN":"下賤な貴様らはナヘマの炎に囲まれ、灰に還るだろう……！！","ENG":"You wretches shall be engulfed by Nahema's flames and turned to ash...!!","TWN":"你們這些卑微的傢伙將會被納赫瑪的火焰吞噬，化為灰燼…！！"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"LACKEY_RIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JUDGE_PRIDE_NULL_NULL","text":{"KOREA":"……집행하라.","JPN":"……執行しろ。","ENG":"...Carry out the sentence.","TWN":"……執行吧。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"LACKEY_RIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LACKEY_RIDE_NULL_NULL","text":{"KOREA":"마왕이시여… 부디…….","JPN":"魔王よ……どうか……","ENG":"O, Demon Lord... please...","TWN":"魔王啊……請你……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"LACKEY_RIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LACKEY_RIDE_NULL_NULL","text":{"KOREA":"저에게… 구원을…….","JPN":"私に……救いを……","ENG":"Grant me... salvation...","TWN":"賜我……救贖……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"LACKEY_RIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHIEF_PRIDE_NULL_NULL","text":{"KOREA":"잘 봐두어라. 저것이 궤도에서 벗어난 뒤틀린 별의 최후이니.","JPN":"しっかり見ておくんだ。あれが軌道から外れ、歪んだ星の最期だ。","ENG":"Watch closely. That is the end of a star that strayed from its path.","TWN":"好好看著吧。那就是偏離軌道的扭曲星星的終結。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"GRACE_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHIEF_PRIDE_NULL_NULL","text":{"KOREA":"저들이 앞다투어 절망을 야기하기 전, 인도자의 혈맥인 우리는 신민들을 올바른 길로 이끌어야 한다.","JPN":"あの者たちが先を争い絶望をもたらす前に、導き手の血脈である私たちは臣民を正しい道へと導かねばならない。","ENG":"Before they can drag the world into despair, it falls to us, the bloodline of the Star Guide, to lead our people down the righteous path.","TWN":"在他們爭先恐後地引發絕望之前，作為引導者血脈的我們必須將臣民引導到正確的道路上。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"GRACE_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHIEF_PRIDE_NULL_NULL","text":{"KOREA":"너는 총명하니 이 아비의 말이 무슨 뜻인지 알겠지?","JPN":"お前は聡明だから、この父の話がわかるな？","ENG":"You're clever. You understand what I mean, don't you?","TWN":"你聰明，應該明白為父的話是什麼意思吧？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"GRACE_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GRACE_CHILD_NULL_NULL","text":{"KOREA":"……예. 아버님.","JPN":"……はい、お父様。","ENG":"...Yes, Father.","TWN":"……是的。父親。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"GRACE_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHIEF_PRIDE_NULL_NULL","text":{"KOREA":"지금의 광경을 잊지 말거라, 그레이스.","JPN":"今の光景を忘れるな、グレース。","ENG":"Remember this sight, Grace.","TWN":"不要忘記現在的景象，葛瑞絲。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"GRACE_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHIEF_PRIDE_NULL_NULL","text":{"KOREA":"네가 판단을 그르친다면, 저 피웅덩이의 주인은 무고한 신민들의 것이 될 것이야.","JPN":"お前が間違った判断をすれば、あの血溜まりの主人は罪なき臣民となるだろう。","ENG":"If you ever fail in judgment, it'll be the innocent who end up in that pool of blood.","TWN":"如果你判斷失誤，那麼那個血泊的主人將會是無辜的臣民。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"GRACE_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"누군가의 뜻에 따라 살아온 인생이지만 불만은 없었다.","JPN":"言われるがままに生きてきた人生だが、不満はなかった。","ENG":"I never resented a life lived according to someone else's will.","TWN":"雖然一直按照別人的意願生活，但我並沒有不滿。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"GRACE_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"주어진 것에 안주하며 묵묵히 소임을 다하는 것은 내게 어려운 일이 아니었으니까.","JPN":"与えられたものに満足し、黙々と役目を果たすのは私にとって難しいことではなかったから。","ENG":"Fulfilling the role I was given without complaint wasn't difficult for me.","TWN":"安於現狀，默默履行職責對我來說並不困難。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"GRACE_CHILD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_A","text":{"KOREA":"인도자님. 요새 통 웃지를 않으시네.","JPN":"導き手、最近まったくお笑いにならないですね。","ENG":"The Star Guide, she hasn't smiled lately.","TWN":"引導者大人，最近都不怎麼笑呢。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_A","text":{"KOREA":"요즘 끼니도 종종 거르시던데, 이러다 탈이라도 나는 건 아닌지 모르겠어.","JPN":"最近は食事を抜くことがあるし、このままだと体調を崩してしまうんじゃないか？","ENG":"She's been skipping meals too. Perhaps she's been pushing herself too hard?","TWN":"最近你經常不按時吃飯，我擔心這樣下去會不會出什麼問題。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"어쩔 수 없지. 최근 연이은 패전으로 왕가에서도 백작가를 독촉하고 있잖아.","JPN":"仕方ない。最近敗戦が続いているから、王家も伯爵家に催促をしてる。","ENG":"She can't help it. After all those losses, the royal family's been pressuring the Count.","TWN":"沒辦法。最近接連的敗戰讓王室也在催促伯爵領地。"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"KNIGH_PRIDE_NULL_B","text":{"KOREA":"당장 사라진 대륙이 한 둘이 아닌데. 무구의 단조를 기다려달라고 할 수 있겠어?","JPN":"次々と大陸が消えているからな。武具の鍛造を待ってくれとはもう言えないんだろう。","ENG":"With continents vanishing left and right, how could we ask them to wait for the forging of an Armament?","TWN":"現在消失的大陸不止一個。能讓我們等著鍛造武具嗎？"},"stage":{"bg":"SKY","slots":{"L":{"char_id":"KNIGH_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGH_PRIDE_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"후계자로서의 교육이 끝났을 무렵, 나는 호위를 거느리고 제국을 누비기 시작했다.","JPN":"後継者としての教育が終わった頃、私は護衛を連れて帝国を回り始めた。","ENG":"Once my training as an heir was complete, I began traveling the Empire with an escort.","TWN":"作為繼承人的教育結束後，我開始帶著護衛在帝國中巡視。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"풍요로운 백작령과는 달리 기근과 죽음이 넘쳐나는 곳이 여정의 태반이었으나.","JPN":"裕福な伯爵領とは違い、飢饉と死が日常化しているところがほとんどであったが。","ENG":"Most of my journey was through famine-stricken lands, nothing like the wealthy County.","TWN":"與富饒的伯爵領地不同，旅程的大部分都是饑荒和死亡的地方。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"내 육신은 상처하나 없이 깨끗했다.","JPN":"私の体は傷一つなく、綺麗だった。","ENG":"Even so, my body remained unscathed.","TWN":"我的身體毫無傷痕，乾淨無瑕。"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};